SELECT u.id, u.username, u.mobile, u.email, u.role_id, u.status, u.created_at, u.updated_at, r.role_name FROM users u JOIN roles r ON u.role_id = r.id WHERE u.deleted_at IS NULL
AND u.username LIKE CONCAT('%', #{query.username}, '%')
AND u.mobile LIKE CONCAT('%', #{query.mobile}, '%')
AND u.role_id = #{query.roleId}
AND u.status = #{query.status}
ORDER BY u.created_at DESC
